public class SwitchYield {
    public static void main(String[] args) {
        String season = "SUMMER";
        int numDays = switch (season) {
            case "SPRING", "FALL" -> 90;
            case "SUMMER" -> {
                System.out.print("暑い！ ");
                yield 92;
            }
            case "WINTER" -> 89;
            default -> 0;
        };
        System.out.println(numDays);
    }
}

public class SwitchMix {
    public static void main(String[] args) {
        int val = 2;
        int result = switch (val) {
            case 1 -> 10;
            case 2:
                yield 20;
            case 3 -> 30;
            default -> 0;
        };
        System.out.println(result);
    }
}

